module RefModule(clk, en, in, out) ;parameter n = 16;  
  input clk, en ;
  input  [n-1:0] in ;
  output [n-1:0] out ;
  wire _tap_clk = clk & {1{1'b1}};

  reg    [n-1:0] out ;
  wire   [n-1:0] next_out ;

  assign next_out = en ? in : out;

  always @(posedge clk)
    out = next_out;endmodule
